const lead = $input.all()[0].json;

// Map LeadFlow Pro fields to generic CRM format
// Adjust field names to match YOUR CRM's API schema
const crmPayload = {
  firstName: (lead.customerName || '').split(' ')[0] || '',
  lastName: (lead.customerName || '').split(' ').slice(1).join(' ') || '',
  email: lead.customerEmail || '',
  phone: lead.customerPhone || '',
  address: lead.fromAddress || '',
  notes: [
    lead.toAddress ? `Destination: ${lead.toAddress}` : '',
    lead.movingDate ? `Date: ${lead.movingDate}` : '',
    (lead.services || []).length ? `Services: ${lead.services.join(', ')}` : '',
    lead.notes || ''
  ].filter(Boolean).join('\n'),
  source: 'LeadFlow Pro - Gmail',
  confidence: lead.confidence || 0,
  leadStatus: 'New',
  emailSubject: lead.rawEmailSubject || '',
  createdAt: lead.createdAt || new Date().toISOString()
};

return [{ json: crmPayload }];
